```rust
unsafe fn set_tpidr_to(p: &mut Proc) {
    let regs_ptr: *mut ArchRegisterFrame = &mut p.regs;
    unsafe {
        core::arch::asm!(
            "msr tpidr_el1, {0}",
            "isb",
            in(reg) regs_ptr,
            options(nomem, nostack, preserves_flags),
        );
    }
}
```
- Saves `&mut p.regs` to `TPIDR_EL1` for trap entry paths to locate frame
- Used by `schedule_next` and `run`

