205	    // SAFETY: `table_pa` came from `alloc_frame`, so it is HHDM-mapped and
206	    // 4 KiB-aligned. Single-threaded boot — no concurrent writer.
207	    unsafe { &*(phys_to_hhdm(table_pa) as *const [u64; PTES_PER_LEVEL]) }
208	}
