211	fn table_mut(table_pa: u64) -> &'static mut [u64; PTES_PER_LEVEL] {
212	    // SAFETY: `table_pa` came from `alloc_frame`, so it is HHDM-mapped and
213	    // 4 KiB-aligned. Single-threaded boot — no concurrent reader/writer.
214	    unsafe { &mut *(phys_to_hhdm(table_pa) as *mut [u64; PTES_PER_LEVEL]) }
