238	/// Return the PA of the child table at `parent[idx]`, allocating and
239	/// linking it if absent.
240	fn ensure_next_table(parent_pa: u64, idx: usize) -> Result<u64, MapError> {
241	    let parent = table_mut(parent_pa);
242	    let desc = parent[idx];
243	    if desc & PTE_VALID != 0 {
244	        return Ok(desc & PA_MASK);
245	    }
246	    let child = alloc_frame().ok_or(MapError::OutOfMemory)?;
247	    parent[idx] = make_table_desc(child.addr());
248	    Ok(child.addr())
249	}
250	
251	/// Recursively free every intermediate table under `table_pa` at the given
252	/// `level` (0 = L0 root, 3 = L3 leaves). Page descriptors at L3 are left
253	/// alone (caller owns leaf frames); the table itself at L3 is freed by
254	/// the L2 recursion call. The L0 root is freed by [`AddrSpace::destroy`].
255	fn free_subtree(table_pa: u64, level: u32) {
256	    if level >= 3 {
257	        // L3 contains page descriptors, not table descriptors — nothing to
258	        // recurse into. The L3 frame itself was already linked at L2 and
259	        // will be freed by the L2 caller.
260	        return;
261	    }
262	    // Snapshot the entries into a local so the HHDM borrow of `table_pa`
263	    // ends before the recursive call (which takes fresh borrows of sibling
264	    // tables — overlapping `&` is fine for shared reads, but copying makes
265	    // the intent unambiguous).
266	    let entries: [u64; PTES_PER_LEVEL] = *table_ref(table_pa);
267	    for desc in entries.iter() {
268	        if *desc & PTE_VALID == 0 {
269	            continue;
270	        }
271	        let child_pa = *desc & PA_MASK;
272	        // Recurse to free grandchildren first, then free this child table.
273	        free_subtree(child_pa, level + 1);
274	        free_frame(Frame::from_addr(child_pa));
275	    }
276	}
