1	//! Slice-3.1b userland bootstrap: per-process address spaces with 8-bit
2	//! ARMv8 ASIDs.
3	//!
4	//! Each of the three EL0 stubs (A, B, C — the slice 2.5 / 2.6 regression
5	//! coverage) gets its own [`AddrSpace`] built from the slice-3.1a frame
6	//! allocator. Code and stack pages are allocated as fresh frames, the
7	//! stub blob is copied in via HHDM (`mm::phys_to_hhdm`), and the
8	//! resulting `(ttbr0_pa, asid)` is stored on the proc slot. The scheduler
9	//! ([`crate::proc::sched::schedule_next`]) installs that TTBR0 on every
10	//! EL1 → EL0 transition.
11	//!
12	//! What slice 3.1a's smoke test exercised in isolation — `AddrSpace::new`,
13	//! `map_page`, `walk_pt`, the free-list reuse on `destroy` — now drives
14	//! the three real EL0 stubs.
15	//!
16	//! What this slice does *not* do:
17	//!   - Recover from page faults. EC=0x20 / EC=0x24 still panic via
18	//!     [`super::exception::el0_sync_unexpected`]; slice 3.1b extends that
19	//!     handler's ISS decoder so the dump is informative, but the policy
20	//!     is still "halt" — real `do_page_fault` + `RTS_PAGEFAULT` land in
21	//!     slice 3.2.
22	//!   - Cross-AS IPC delivery. The SVC handler runs in the caller's TTBR0,
23	//!     so single-AS reads in `ipc::message` still walk correctly; slice
24	//!     3.4's HHDM-walk redesign of `flush_deliver_msg` swaps that out
25	//!     once VM exists.
26	//!   - Install a kernel-shared global mapping for the EL0 stubs. The
27	//!     code page is mapped RO + EL0-executable into each per-proc AS
28	//!     individually (zero shared frames).
29	
30	use core::sync::atomic::Ordering;
31	
32	use minix4_kernel_shared::callnr::{KERNEL_CALL, SYS_GETINFO};
33	use minix4_kernel_shared::com::{RS_PROC_NR, SYSTEM, boot_endpoint};
34	use minix4_kernel_shared::{PrivId, ProcNr};
35	
36	use crate::arch::aarch64::addrspace::{AddrSpace, Prot};
37	use crate::arch::aarch64::asid::alloc_asid;
38	use crate::arch::aarch64::mmu::{self, PAGE_SIZE, flush_icache_range};
39	use crate::mm::{Frame, alloc_frame, phys_to_hhdm};
40	use crate::proc::bitmap::{set_call_bit, set_sys_bit};
41	use crate::proc::flags::{BILLABLE, PREEMPTIBLE, SRV_T, SYS_PROC, USR_T};
42	use crate::proc::sched;
43	use crate::proc::table::{priv_slot_mut, proc_index, proc_slot_mut, proc_table_ref};
44	use crate::proc::{Priv, Proc};
45	
46	// ----- EL0 virtual addresses ------------------------------------------------
47	
48	/// VA at which stub A's code page is mapped.
49	pub const USER_CODE_VA_A: u64 = 0x0040_0000; // 4 MiB
50	/// VA at which stub A's stack page is mapped.
51	pub const USER_STACK_VA_A: u64 = 0x0080_0000; // 8 MiB
52	
53	/// VA at which stub B's code page is mapped.
54	pub const USER_CODE_VA_B: u64 = 0x0041_0000;
55	/// VA at which stub B's stack page is mapped.
56	pub const USER_STACK_VA_B: u64 = 0x0081_0000;
57	
58	/// VA at which stub C's code page is mapped.
59	pub const USER_CODE_VA_C: u64 = 0x0042_0000;
60	/// VA at which stub C's stack page is mapped.
61	pub const USER_STACK_VA_C: u64 = 0x0082_0000;
62	
63	/// First proc-table slot beyond the boot image — `ProcNr(11)`.
64	const STUB_A_PROC_NR: ProcNr = ProcNr::new(11);
65	/// Second stub slot, just after A.
66	const STUB_B_PROC_NR: ProcNr = ProcNr::new(12);
67	/// Slice-2.6 kernel-call client. Slot 13 — one past the slice-2.5 pair.
68	const STUB_C_PROC_NR: ProcNr = ProcNr::new(13);
69	
70	/// Privilege-table slots for the three stubs. Boot image uses 0..=15;
71	/// 16, 17, and 18 are the first free entries.
72	const STUB_A_PRIV_ID: PrivId = PrivId::new(16);
73	const STUB_B_PRIV_ID: PrivId = PrivId::new(17);
74	const STUB_C_PRIV_ID: PrivId = PrivId::new(18);
75	
76	// SPSR_EL1 to install on each stub's `eret`. Matches slice 2.4: IRQs
77	// unmasked at EL0 (bit 7 = 0), debug + SError + FIQ masked. EL0t.
78	const STUB_SPSR_EL0: u64 = 0x340;
79	
80	// ----- EL0 stub blobs (linked into the kernel image by `user_stub.S`) ------
81	
82	unsafe extern "C" {
83	    static _user_stub_a_start: u8;
84	    static _user_stub_a_end: u8;
85	    static _user_stub_b_start: u8;
86	    static _user_stub_b_end: u8;
87	    static _user_stub_c_start: u8;
88	    static _user_stub_c_end: u8;
89	}
90	
91	// ----- Bootstrap ----------------------------------------------------------
92	
93	/// Build three per-process address spaces (one per EL0 stub), populate
94	/// their proc + priv slots, and enqueue them on the scheduler.
95	///
96	/// Compared to slice 2.5/2.6 this:
97	///   - Drops the static `L0_TABLE`/.../`L3_STACK_TABLE` + `USER_*_PAGE_*`
98	///     arrays. Every frame is allocated from `mm::alloc_frame`.
99	///   - Hands each stub its own `(ttbr0_pa, asid)` via
100	///     [`build_stub`] + [`AddrSpace`].
101	///   - No longer installs a single TTBR0 from boot context; the scheduler
102	///     installs per-proc TTBR0 + ASID on every EL1 → EL0 transition.
103	///
104	/// SAFETY: must be called exactly once from `kmain` after `proc::init`,
105	/// `mm::set_hhdm_offset`, and `mm::init_from_limine_memmap`. Single-
106	/// threaded boot context; no other reference into the named proc slots
107	/// or the frame allocator may be live concurrently.
108	pub unsafe fn userland_bootstrap() {
109	    // 1. Verify Limine left MAIR_EL1 + TCR_EL1 in the shape our walker
110	    //    + per-proc TTBR0 install expect. The slice-3.1b TCR_EL1.AS = 0
111	    //    assert was added inside `assert_tcr_el1_ttbr0_ready`.
112	    mmu::assert_mair_normal_wb();
113	    mmu::assert_tcr_el1_ttbr0_ready();
114	
115	    // 2. Clear TCR_EL1.EPD0 once. Per-proc TTBR0 install happens at every
116	    //    context switch via `proc::sched::schedule_next`.
117	    // SAFETY: DAIF still masked from Limine handoff; single-threaded boot.
118	    unsafe { mmu::enable_ttbr0_walks_once() };
119	
120	    // 3. Build each stub. Sequential calls — each build_stub allocates
121	    //    fresh frames + a fresh AddrSpace and writes its proc slot.
122	    // SAFETY: single-threaded boot; build_stub only touches its own
123	    // allocated state + the named proc slot.
124	    unsafe {
125	        build_stub(
126	            STUB_A_PROC_NR,
127	            STUB_A_PRIV_ID,
128	            b'A',
129	            &_user_stub_a_start,
130	            &_user_stub_a_end,
131	            USER_CODE_VA_A,
132	            USER_STACK_VA_A,
133	        );
134	        build_stub(
135	            STUB_B_PROC_NR,
136	            STUB_B_PRIV_ID,
137	            b'B',
138	            &_user_stub_b_start,
139	            &_user_stub_b_end,
140	            USER_CODE_VA_B,
141	            USER_STACK_VA_B,
142	        );
143	        build_stub(
144	            STUB_C_PROC_NR,
145	            STUB_C_PRIV_ID,
146	            b'C',
147	            &_user_stub_c_start,
148	            &_user_stub_c_end,
149	            USER_CODE_VA_C,
150	            USER_STACK_VA_C,
151	        );
152	    }
153	
154	    // 4. Install priv slots — unchanged from slice 2.6.
155	    // SAFETY: single-threaded boot; sequential mutable borrows on
156	    // priv-table slots 16, 17, 18.
157	    unsafe { install_stub_privs() };
158	
159	    // 5. Enqueue all three on the scheduler.
160	    // SAFETY: single-threaded boot; no other PROC_TABLE / RUNQ borrows
161	    // live at this point.
162	    unsafe {
163	        sched::enqueue(STUB_A_PROC_NR);
164	        sched::enqueue(STUB_B_PROC_NR);
165	        sched::enqueue(STUB_C_PROC_NR);
166	    }
167	
168	    // 6. One-shot diagnostic: dump per-proc (ttbr0_pa, asid) so the
169	    //    boot log proves each stub has its own distinct AS.
170	    //    SAFETY: single-threaded boot; read-only.
171	    unsafe { print_addrspace_summary() };
172	}
173	
174	/// Build one stub's address space: allocate L0 + code + stack frames,
175	/// copy the stub blob into the code frame, install RX/RW mappings, and
176	/// write `(ttbr0_pa, asid)` into the proc slot.
177	///
178	/// `aspace` is intentionally `mem::forget`-ed at the end: the page-table
179	/// tree is now owned by the proc (via its `ttbr0_pa`); the kernel will
180	/// only reach into it again via HHDM walks. `AddrSpace::destroy` would
181	/// recursively free every L1/L2/L3 frame plus the L0 root, which is
182	/// exactly what we don't want.
183	///
184	/// SAFETY: single-threaded boot; this is the only writer of `nr`'s proc
185	/// slot. `stub_start..stub_end` must be a valid contiguous rodata range
186	/// in the kernel image; the linker guarantees both.
187	unsafe fn build_stub(
188	    nr: ProcNr,
189	    priv_id: PrivId,
190	    id: u8,
191	    stub_start: *const u8,
192	    stub_end: *const u8,
193	    code_va: u64,
194	    stack_va: u64,
195	) {
196	    // Per-proc page-table tree. AddrSpace::new allocates and zeroes the
197	    // L0 root via the frame allocator.
198	    let mut aspace =
199	        AddrSpace::new().expect("AddrSpace::new failed during userland_bootstrap");
200	    let ttbr0_pa = aspace.ttbr0_pa;
201	
202	    // Code frame: allocate, copy stub bytes in via HHDM, flush I-cache,
203	    // map RO + EL0-executable.
204	    let code_frame = alloc_frame()
205	        .expect("code frame alloc failed during userland_bootstrap");
206	    // SAFETY: stub_start/stub_end are rodata symbols inside the kernel
207	    // image; the new code frame is exclusively ours (just allocated, not
208	    // yet mapped into any AS) and HHDM-mapped.
209	    unsafe { copy_stub_into_frame(code_frame, stub_start, stub_end) };
210	    aspace
211	        .map_page(code_va, code_frame.addr(), Prot::RO_CODE)
212	        .expect("map_page(code) during userland_bootstrap");
213	
214	    // Stack frame: zeroed by `alloc_frame`, mapped RW + EL0-no-execute.
215	    let stack_frame = alloc_frame()
216	        .expect("stack frame alloc failed during userland_bootstrap");
217	    aspace
218	        .map_page(stack_va, stack_frame.addr(), Prot::RW_DATA)
219	        .expect("map_page(stack) during userland_bootstrap");
220	
221	    // Hand the AddrSpace's root over to the proc slot.
222	    // SAFETY: single-threaded boot; this is the only `&mut Proc` borrow
223	    // at this nr right now.
224	    let asid = unsafe { alloc_asid() };
225	    unsafe {
226	        let p = proc_slot_mut(nr).expect("stub proc slot in range");
227	        populate_stub_slot(
228	            p,
229	            nr,
230	            priv_id,
231	            id,
232	            code_va,
233	            stack_va + PAGE_SIZE as u64,
234	            ttbr0_pa,
235	            asid,
236	        );
237	    }
238	
239	    // The page-table tree is durable via `ttbr0_pa`. Drop the AddrSpace
240	    // value without running its (no-op-today, but defensively forget'd)
241	    // destructor — leaving `AddrSpace::destroy` reserved for exit/exec
242	    // paths that actually want to tear an AS down.
243	    core::mem::forget(aspace);
244	}
245	
246	/// Copy `[stub_start, stub_end)` into `frame` (resolved via HHDM) and
247	/// flush the I-cache so the upcoming EL0 fetch sees the new bytes.
248	///
249	/// SAFETY: `frame` must be exclusively owned (not yet mapped anywhere)
250	/// and the HHDM mapping for its PA must be live. `stub_start..stub_end`
251	/// must be a valid byte range in the kernel image.
252	unsafe fn copy_stub_into_frame(
253	    frame: Frame,
254	    stub_start: *const u8,
255	    stub_end: *const u8,
256	) {
257	    // SAFETY: end >= start by linker layout; offset_from is well-defined
258	    // on a single rodata symbol pair.
259	    let len = unsafe { stub_end.offset_from(stub_start) } as usize;
260	    assert!(len > 0 && len <= PAGE_SIZE);
261	    // SAFETY: caller's invariants hold; we have the sole pointer to this
262	    // frame, and HHDM is the only mapping.
263	    unsafe {
264	        let dst = phys_to_hhdm(frame.addr()) as *mut u8;
265	        core::ptr::copy_nonoverlapping(stub_start, dst, len);
266	        flush_icache_range(dst as u64, len);
267	    }
268	}
269	
270	/// Write all per-stub fields into `p`. Extends slice 2.5's helper with
271	/// `ttbr0_pa` and `asid` — the rest mirrors slice 2.6.
272	fn populate_stub_slot(
273	    p: &mut Proc,
274	    nr: ProcNr,
275	    priv_id: PrivId,
276	    id: u8,
277	    entry_va: u64,
278	    stack_top: u64,
279	    ttbr0_pa: u64,
280	    asid: u8,
281	) {
282	    // Name: `id` followed by "-stub\0..." padding. Lets the clock tick
283	    // handler print `name[0]` to identify which stub is running.
284	    p.name = [0; 16];
285	    p.name[0] = id;
286	    p.name[1] = b'-';
287	    p.name[2] = b's';
288	    p.name[3] = b't';
289	    p.name[4] = b'u';
290	    p.name[5] = b'b';
291	
292	    p.nr = nr;
293	    p.endpoint = boot_endpoint(nr);
294	    p.priv_id = Some(priv_id);
295	    p.priority = crate::proc::table::SRV_Q;
296	    // 5 ticks per quantum = 50 ms at 100 Hz.
297	    p.quantum_ms = 5;
298	    p.quantum_left = p.quantum_ms as u64;
299	
300	    // EL0 entry state.
301	    p.regs.elr_el1 = entry_va;
302	    p.regs.sp_el0 = stack_top;
303	    p.regs.spsr_el1 = STUB_SPSR_EL0;
304	
305	    // Per-proc address space. Stored on the slot; the scheduler reads
306	    // both on every EL1 → EL0 transition.
307	    p.ttbr0_pa = ttbr0_pa;
308	    p.asid = asid;
309	
310	    // Run-queue link starts cleared — `sched::enqueue` sets it.
311	    p.next_ready = None;
312	
313	    // Mark runnable.
314	    p.rts_flags.store(0, Ordering::Relaxed);
315	}
316	
317	/// Install priv slots for A, B, C. Unchanged from slice 2.6.
318	///
319	/// SAFETY: single-threaded boot; touches priv-table slots 16, 17, 18
320	/// sequentially.
321	unsafe fn install_stub_privs() {
322	    // SAFETY: sequential mutable borrow.
323	    unsafe {
324	        install_one_stub_priv(STUB_A_PRIV_ID, STUB_A_PROC_NR, STUB_B_PRIV_ID);
325	    }
326	    // SAFETY: A's borrow has been dropped.
327	    unsafe {
328	        install_one_stub_priv(STUB_B_PRIV_ID, STUB_B_PROC_NR, STUB_A_PRIV_ID);
329	    }
330	    // SAFETY: B's borrow has been dropped.
331	    unsafe {
332	        install_stub_c_priv();
333	    }
334	}
335	
336	/// Install stub C's priv slot. Differs from the A/B helper: trap_mask =
337	/// USR_T (SENDREC only), ipc_to opened just to SYSTEM, k_call_mask
338	/// opened just to `SYS_GETINFO`.
339	///
340	/// SAFETY: single-threaded boot; mutates only priv-table slot
341	/// `STUB_C_PRIV_ID`.
342	unsafe fn install_stub_c_priv() {
343	    let system_priv_id = {
344	        // SAFETY: read-only snapshot; no live `&mut Proc` here.
345	        let table = unsafe { proc_table_ref() };
346	        let idx = proc_index(SYSTEM).expect("SYSTEM in proc table");
347	        table[idx]
348	            .priv_id
349	            .expect("SYSTEM priv populated by proc::init")
350	    };
351	
352	    // SAFETY: priv index in-range; no overlapping reference held.
353	    let pr: &mut Priv =
354	        unsafe { priv_slot_mut(STUB_C_PRIV_ID).expect("stub C priv slot in range") };
355	    pr.id = STUB_C_PRIV_ID;
356	    pr.proc_nr = Some(STUB_C_PROC_NR);
357	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
358	    pr.trap_mask = USR_T;
359	    pr.ipc_to.fill(0);
360	    set_sys_bit(&mut pr.ipc_to, system_priv_id);
361	    pr.k_call_mask.fill(0);
362	    set_call_bit(&mut pr.k_call_mask, (SYS_GETINFO - KERNEL_CALL) as usize);
363	    pr.notify_pending.fill(0);
364	    pr.asyn_pending.fill(0);
365	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
366	}
367	
368	/// Set the per-stub priv slot. `peer_priv_id` is the only target the
369	/// stub is permitted to send/notify (encoded as a single bit in
370	/// `ipc_to`).
371	///
372	/// SAFETY: single-threaded boot; mutates only the priv slot at `id`.
373	unsafe fn install_one_stub_priv(id: PrivId, owner: ProcNr, peer_priv_id: PrivId) {
374	    // SAFETY: priv index in-range; no overlapping reference held.
375	    let pr: &mut Priv =
376	        unsafe { priv_slot_mut(id).expect("stub priv slot in range") };
377	    pr.id = id;
378	    pr.proc_nr = Some(owner);
379	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
380	    pr.trap_mask = SRV_T;
381	    pr.ipc_to.fill(0);
382	    set_sys_bit(&mut pr.ipc_to, peer_priv_id);
383	    pr.k_call_mask.fill(0);
384	    pr.notify_pending.fill(0);
385	    pr.asyn_pending.fill(0);
386	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
387	}
388	
389	/// Print one line per stub showing its `(ttbr0_pa, asid)`. Run once at
390	/// the end of `userland_bootstrap`; proves each stub has a distinct
391	/// per-proc address space.
392	///
393	/// SAFETY: single-threaded boot; read-only borrows on proc slots 11/12/13.
394	unsafe fn print_addrspace_summary() {
395	    use crate::arch::aarch64::uart::Pl011;
396	    use core::fmt::Write;
397	    let mut uart = Pl011::new();
398	    let _ = writeln!(uart);
399	    for &nr in &[STUB_A_PROC_NR, STUB_B_PROC_NR, STUB_C_PROC_NR] {
400	        // SAFETY: sequential read-only borrow of the slot; no other
401	        // reference held while we read.
402	        let p = unsafe { proc_slot_mut(nr).expect("stub slot in range") };
403	        let _ = writeln!(
404	            uart,
405	            "[as] stub {} nr={} ttbr0_pa={:#x} asid={}",
406	            p.name[0] as char,
407	            p.nr.get(),
408	            p.ttbr0_pa,
409	            p.asid,
410	        );
411	    }
412	}
