    /// Next process in the receiver's caller queue.
    pub q_link: Option<ProcNr>,
    /// Endpoint we're trying to RECEIVE from (or `ANY`).
    pub getfrom_e: Endpoint,
    /// Endpoint we're trying to SEND to.
